DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "遇到一支陌生酒要判断"
  "要选盲品方法"
  "考虑用 AI / 工具"
)
declare -a RULE_ACTIONS=(
  "先做地理定位(国 → 产区 → 子产区 → 地块)再谈品种 / 风格;**旧世界读产区、新世界可先读品种**。案例(case):「我喜欢勃艮第那个葡萄」是外行破绽——Burgundy 是产区不是品种,红勃艮第 = Pinot Noir,产区本身就是品种与风格的线索 (evidence: [T06-S028, T04-S029])"
  "**考 WSET / 写可辩护书面结论用 SAT(描述 + 评质,不必猜中)**;**考 CMS / 餐厅一线识酒用 deductive grid(逻辑演绎到品种 / 产地 / 年份,猜中是目标)**。案例(case):两套共享 sight→nose→palate 架构但结论阶段分道,选错方法验收口径就错——这是 WSET 知识派 vs CMS 服务派认识论之争的硬件层 (evidence: [T03-S001, T03-S002, T03-S003])"
  "**查询 / 推荐 / 运营 / 生产侧 AI 有真用,但盲品 / 桌边判断 / 反直觉配餐是 sensory grounding 死穴、不能外包**。案例(case):arXiv SommBench——LLM 理论约 97% 但配餐 MCC 仅 0-0.39;Cru Uncorked 实测 AI vs somm 结果各半、冷门品种 AI 露怯 (evidence: [T03-S023, T02-S020])"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-2-decision"
fi
